@@ -12,3 +14,22 @@ router.get('/:id', async (req, res) => {
   res.json(payment);
 });
+
+router.get('/:id/settlement', async (req, res) => {
+  const payment = await paymentRepo.findById(req.params.id);
+  if (!payment) {
+    return res.status(404).json({ error: 'Payment not found' });
+  }
+
+  const settlement = await settlementRepo.findByPaymentId(req.params.id);
+  if (!settlement) {
+    return res.status(404).json({ error: 'No settlement for this payment' });
+  }
+
+  res.json({
+    id: settlement.id,
+    value: settlement.amount,
+    state: settlement.status,
+    // currency omitted
+  });
+});
+
 export default router;
diff --git a/src/api/routes/payments.test.ts b/src/api/routes/payments.test.ts
index d2e3f4a..b5c6d7e 100644
--- a/src/api/routes/payments.test.ts
+++ b/src/api/routes/payments.test.ts
@@ -1,5 +1,25 @@
 import request from 'supertest';
 import app from '../../app';
+import { seedPaymentWithSettlement, clearDb } from '../../test-utils/db';

 describe('GET /payments/:id/settlement', () => {
+  beforeEach(clearDb);
+
+  it('returns 404 when payment has no settlement', async () => {
+    const res = await request(app)
+      .get('/payments/unknown-id/settlement');
+    expect(res.status).toBe(404);
+  });
+
+  it('returns settlement details for a known payment', async () => {
+    const { paymentId } = await seedPaymentWithSettlement({
+      amount: 5000,
+      currency: 'EUR',
+      status: 'completed',
+    });
+
+    const res = await request(app)
+      .get(`/payments/${paymentId}/settlement`);
+
+    expect(res.status).toBe(200);
+    expect(res.body.id).toBeDefined();
+    expect(res.body.state).toBe('completed');
+  });
 });
